<?php namespace Database\Seeders; use App\Enums\{AssetStatus,MaintenanceStatus,Priority,WorkOrderStatus};use App\Models\{Asset,PreventiveMaintenance,User,WorkOrder};use Illuminate\Database\Seeder;use Illuminate\Support\Facades\Hash;use Spatie\Permission\Models\Role;
class DatabaseSeeder extends Seeder{public function run():void{$roles=collect(['Administrator','Supervisor','Technician'])->map(fn($r)=>Role::firstOrCreate(['name'=>$r,'guard_name'=>'web']));$admin=User::create(['name'=>'Avery Stone','email'=>'admin@mantsoft.test','password'=>Hash::make('password'),'phone'=>'(555) 010-1000','avatar'=>'AS','status'=>'active']);$admin->assignRole('Administrator');foreach(range(1,9) as $i){$u=User::create(['name'=>fake()->name(),'email'=>"tech{$i}@mantsoft.test",'password'=>Hash::make('password'),'phone'=>fake()->phoneNumber(),'avatar'=>fake()->lexify('??'),'status'=>fake()->randomElement(['active','active','active','inactive'])]);$u->assignRole($i<3?'Supervisor':'Technician');}$categories=['HVAC','Production','Electrical','Fleet','Facilities'];$locations=['Plant A','Plant B','Warehouse','Office','Loading Dock'];foreach(range(1,20) as $i){Asset::create(['code'=>sprintf('AST-%04d',$i),'name'=>fake()->randomElement(['Air Compressor','Packaging Line','Forklift','Generator','Chiller','Conveyor','Pump']).' '.$i,'category'=>fake()->randomElement($categories),'location'=>fake()->randomElement($locations),'manufacturer'=>fake()->company(),'model'=>strtoupper(fake()->bothify('MX-###')),'serial_number'=>strtoupper(fake()->bothify('SN??####')),'purchase_date'=>fake()->dateTimeBetween('-6 years','-3 months'),'status'=>fake()->randomElement(AssetStatus::cases()),'description'=>fake()->sentence(14)]);} $assets=Asset::all();$techs=User::role(['Technician','Supervisor'])->get();foreach(range(1,50) as $i){$status=fake()->randomElement(WorkOrderStatus::cases());$wo=WorkOrder::create(['number'=>sprintf('WO-%05d',$i),'title'=>fake()->randomElement(['Inspect vibration','Replace worn belt','Calibrate sensor','Resolve leak','Annual safety check','Motor temperature alarm']),'description'=>fake()->paragraph(),'asset_id'=>$assets->random()->id,'technician_id'=>$techs->random()->id,'priority'=>fake()->randomElement(Priority::cases()),'status'=>$status,'start_date'=>fake()->dateTimeBetween('-30 days','+5 days'),'due_date'=>fake()->dateTimeBetween('now','+45 days'),'completion_date'=>$status===WorkOrderStatus::Completed?fake()->dateTimeBetween('-20 days','now'):null]);foreach([WorkOrderStatus::Pending,$status] as $s){$wo->timeline()->create(['status'=>$s,'note'=>$s->label().' by demo workflow','changed_at'=>now()->subDays(fake()->numberBetween(1,20))]);}}foreach(range(1,30) as $i){PreventiveMaintenance::create(['asset_id'=>$assets->random()->id,'frequency'=>fake()->randomElement(['Weekly','Monthly','Quarterly','Semiannual','Annual']),'last_maintenance'=>fake()->dateTimeBetween('-120 days','-10 days'),'next_maintenance'=>fake()->dateTimeBetween('-5 days','+60 days'),'technician_id'=>$techs->random()->id,'status'=>fake()->randomElement(MaintenanceStatus::cases())]);}}}
